"use strict";(self.webpackChunkTartaria=self.webpackChunkTartaria||[]).push([[717],{3201:(e,l,i)=>{i.r(l),i.d(l,{data:()=>a});const a={key:"v-29aeb15c",path:"/aphorisms/",title:"Афоризмы",lang:"ru-RU",frontmatter:{sidebarDepth:2},excerpt:"",headers:[{level:2,title:"Самуил Яковлевич Маршак",slug:"самуил-яковлевич-маршак",children:[]},{level:2,title:"Станислав Ежи Лец",slug:"станислав-ежи-лец",children:[]},{level:2,title:"Татьяна",slug:"татьяна",children:[]},{level:2,title:"Уинстон Черчель",slug:"уинстон-черчель",children:[]},{level:2,title:"Шота Руставели",slug:"шота-руставели",children:[]},{level:2,title:"Разное",slug:"разное",children:[]},{level:2,title:"Из фильмов",slug:"из-фильмов",children:[{level:3,title:"Викинги",slug:"викинги",children:[]},{level:3,title:"Дедвуд",slug:"дедвуд",children:[]}]}],filePathRelative:"aphorisms/README.md",git:{updatedTime:1735495719e3,contributors:[{name:"blackchestnut",email:"alexander.kalinichev@gmail.com",commits:8},{name:"Alexander",email:"alexander.kalinichev@gmail.com",commits:2},{name:"Alex",email:"alexander.kalinichev@gmail.com",commits:1}]}}},8802:(e,l,i)=>{i.r(l),i.d(l,{default:()=>h});const a=(0,i(6252).uE)('<h1 id="афоризмы" tabindex="-1"><a class="header-anchor" href="#афоризмы" aria-hidden="true">#</a> Афоризмы</h1><h2 id="самуил-яковлевич-маршак" tabindex="-1"><a class="header-anchor" href="#самуил-яковлевич-маршак" aria-hidden="true">#</a> Самуил Яковлевич Маршак</h2><blockquote><p>(перевод Джона Харингтона)</p></blockquote><ul><li>Мятеж не может кончиться удачей, - в противном случае его звут иначе</li></ul><h2 id="станислав-ежи-лец" tabindex="-1"><a class="header-anchor" href="#станислав-ежи-лец" aria-hidden="true">#</a> Станислав Ежи Лец</h2><ul><li>В действительности все не так, как на самом деле</li></ul><h2 id="татьяна" tabindex="-1"><a class="header-anchor" href="#татьяна" aria-hidden="true">#</a> Татьяна</h2><ul><li>Если было б всё так просто - был б ты маленького роста</li><li>Остановишь свои дела - и жизнь свою остановишь</li><li>Родишься - не поймешь, умрешь - не узнаешь</li><li>Старость - не радость, мудрость - не подарок</li><li>Творог не мясо - готовить не надо</li><li>Хорошо ли вам было сегодня, вы, узнаете только завтра</li></ul><h2 id="уинстон-черчель" tabindex="-1"><a class="header-anchor" href="#уинстон-черчель" aria-hidden="true">#</a> Уинстон Черчель</h2><ul><li>Если тебя ненавидят, значит ты в своей жизни, что-то отстаивал</li></ul><h2 id="шота-руставели" tabindex="-1"><a class="header-anchor" href="#шота-руставели" aria-hidden="true">#</a> Шота Руставели</h2><ul><li>Кто себе друзей не ищет, самому себе он враг</li><li>Всех богатств добытых лучше добыванье доброй славы</li><li>Лучше смерть, но смерть со славой, чем постыдный в жизни путь</li><li>Другу верный друг поможет, не страшит его беда</li><li>Сердце он отдаст за сердце, а любовь - в пути звезда</li></ul><h2 id="разное" tabindex="-1"><a class="header-anchor" href="#разное" aria-hidden="true">#</a> Разное</h2><ul><li>Всё, сотворённое ранее, распадётся, не повторяясь</li><li>Освободите себя от надежды, что море когда-нибудь успокоится</li></ul><h2 id="из-фильмов" tabindex="-1"><a class="header-anchor" href="#из-фильмов" aria-hidden="true">#</a> Из фильмов</h2><h3 id="викинги" tabindex="-1"><a class="header-anchor" href="#викинги" aria-hidden="true">#</a> Викинги</h3><blockquote><p>(англ. Vikings)</p></blockquote><ul><li>То что мы заслужеваем и то, что получаем не всегда совпадает. Похоже богов не соишком беспокоит справедливость</li></ul><h3 id="дедвуд" tabindex="-1"><a class="header-anchor" href="#дедвуд" aria-hidden="true">#</a> Дедвуд</h3><blockquote><p>(англ. Deadwood)</p></blockquote><ul><li>От тех кто хочет оправдаться несчастья столько же, сколько и от тех, кто замыслил зло</li></ul>',21),r={},h=(0,i(3744).Z)(r,[["render",function(e,l){return a}]])},3744:(e,l)=>{l.Z=(e,l)=>{for(const[i,a]of l)e[i]=a;return e}}}]);